```html
<html>
  <head>
  %@LW_pgstart@@
    <title>Invoice</title>
    <style>
      /* table, th, td {
        border: 1px solid black;
      } */

      body {
        background-color: #fff;
        font-family: sans-serif;
        padding-left: 30px;
        padding-top: 30px;
        padding-right: 30px;
        padding-bottom: 30px;
        width: 840px;
        height: 850px;
      }

      table {
        border-collapse: collapse;
        width: 100%;
        margin-bottom: 20px;
      }

      th {
        height: 25px;
        font-weight: bold;
      }

      td {
        word-wrap: break-word;
      }

      th, td {
        font-size: 12px;
      }

      #head table, #head td, #head th {
        border: none !important;
      }

      @media print and (min-resolution: 144dpi) {
        .no-print, .no-print * {
          display: none !important;
        }
      }

      .bt {
        border-top: 1px solid;
      }

      .br {
        border-right: 1px solid;
      }

      .bb {
        border-bottom: 1px solid;
      }

      .bl {
        border-left: 1px solid;
      }

      .ba {
        border: 1px solid;
      }

      .p {
        padding: 5px;
      }

      .bold {
        font-weight: bold;
      }
    </style>

    <script defer>
      function capitalizeWords(str) {
        return str
          .toLowerCase()
          .split(' ')
          .map(word => word.charAt(0).toUpperCase() + word.slice(1))
          .join(' ');
      }

      document.addEventListener('DOMContentLoaded', function () {
        const tdElements = document.querySelectorAll('.bilang');
        tdElements.forEach(td => {
          td.textContent = capitalizeWords(td.textContent.trim());
        });
      });


      document.addEventListener('DOMContentLoaded', function () {
        const elements = document.querySelectorAll('.angka');
        elements.forEach(td => {
          const num = parseFloat(td.textContent.replace(/,/g, ''));
          if (!isNaN(num)) {
            td.textContent = num.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
          }
        });
      });
    </script>
  </head>
  <body text="#000" style="background-color:%LW_color_bg%">

    LW_pgstart@%

    %@LW_prowno_0@@
  <button class="no-print" onclick="window.print()">Print</button>
  <table>
    <tr>
      <td style="width: 40%; vertical-align: center;"><img src="../menu/Lpx/sinter_logo.png" style="width: 47px; height: 47px;"/></td>
      <td style="width: 20%; vertical-align: center; text-align: center;"><span style="font-size: 14px;"><strong>Purchase Order Confirmation</strong></span><br></td>
      <td style="width: 40%; vertical-align: bottom; text-align: right;"><span>Kepada Yth,</span><br></td>
    </tr>
  	<tr><td><br></td></tr>
    <tr>
      <td><span>%@LW_PField_TableDS(gl820a,tb_descr,"0")@%</span><br></td>
      <td style="text-align: center;"><span style="font-size: 14px;"><strong>Order Date</strong> : %@LW_PField_DtoStr(po_dtfak,DD/MM/YY)@%</span><br></td>
      <td style="text-align: right;"><span>%@LW_PField_po_Name@%</span><br></td>
    </tr>
    <tr>
      <td><span style="font-size: 12px;">%@LW_PField_TableDS(gl820a,tb_adr1,"0")+' '+TableDS(gl820a,tb_adr2,"0")@%</span><br></td>
      <td style="text-align: center;"><span style="font-size: 14px;"><strong>Due Date</strong> : %@LW_PField_DtoStr(po_dtdue,DD/MM/YY)@%</span><br></td>
      <td style="text-align: right;"><span style="font-size: 12px;">%@LW_PField_po_adr1@%</span><br></td>
    </tr>
    <tr>
      <td><span style="font-size: 12px;">%@LW_PField_TableDS(gl820a,tb_adr3,"0")@%</span><br></td>
      <td style="text-align: center;"><span style="font-size: 14px;"><strong>Order No</strong> : %@LW_PField_po_nopo@%</span><br></td>
      <td style="text-align: right;"><span style="font-size: 12px;">%@LW_PField_po_adr2@%</span><br></td>
    </tr>
  </table>

  <table>
    <thead>
      <tr class="bb">
        <th class="p">No</th>
        <th class="p" style="text-align: left;">Kode</th>
        <th class="p" style="text-align: left;">No.Part</th>
        <th class="p" style="text-align: left;">Nama Barang</th>
        <th class="p" style="text-align: left;">Deskripsi</th>
        <th class="p" style="text-align: right;">Qty</th>
        <th class="p" style="text-align: left;">Satuan</th>
        <th class="p" style="text-align: right;">Harga</th>
        <th class="p" style="text-align: right;">Disc.(%)</th>
        <th class="p" style="text-align: right;">Jumlah</th>
      </tr>
    </thead>
    LW_prowno_0@%
    <tbody>
      %@LW_prowno_10@@
      <tr style="vertical-align: text-top;">
        %@LW_PRow_add@1@%
        <td class="p" style="text-align: center;">%@LW_PField__drow@%</td>
        <td class="p">%@LW_PField_po_itemid@%</td>
        <td class="p">%@LW_PField_TableDs(ic010a,im_partno,po_itemid)@%</td>
        <td class="p">%@LW_PField_TableDs(ic010a,im_nabar_1,po_itemid)@%</td>
        <td class="p">%@LW_PField_TableDs(ic010a,im_nabar_3,po_itemid)@%</td>
        <td class="p" style="text-align: right;">%@LW_PField_po_qty@N/2,N@%</td>
        <td class="p">%@LW_PField_po_uom@%</td>
        <td class="p" style="text-align: right;"><span class="angka">%@LW_PField_po_upricei@%</span> Rp</td>
        <td class="p" style="text-align: right;"><span class="angka">%@LW_PField_po_qdis@%</td>
        <td class="p" style="text-align: right;"><span class="angka">%@LW_PField_po_hrg@%</span> Rp</td>
      </tr>
      LW_prowno_10@%
      %@LW_prowno_299@@
      <tr>
        <td colspan="7">
          <table>
            <tr><td><b class="bold">Terbilang</b>: <span class="bilang">%@LW_PField_Bilang(po_harga, 'Rupiah', 0, '')@%</span></td></tr>
            <tr><td>%@LW_PField_TableDS(ic820a,tb_remark,po_whs)@%</td></tr>
            <tr><td>%@LW_PField_TableDS(ic820a,tb_remark2,po_whs)@%</td></tr>
            <tr><td>%@LW_PField_TableDS(ic820a,tb_remark3,po_whs)@%</td></tr>
            <tr><td></td></tr>
          </table>
        </td>
        <td colspan="3">
          <table class="bt"> 
            <tr><td class="bbd p bold" style="text-align: end;">Sub Total :</td><td style="text-align: right;"><span class="angka">%@LW_PField_po_hrg@%</span> Rp</td></tr>
            <tr><td class="bbd p bold" style="text-align: end;">Diskon :</td><td style="text-align: right;"><span class="angka">%@LW_PField_po_hpot+po_hpot2+po_hpot3+po_hpot4+po_hpot5@%</span> Rp</td></tr>
            <tr><td class="bbd p bold" style="text-align: end;">PPn :</td><td style="text-align: right;"><span class="angka">%@LW_PField_po_htax@%</span> Rp</td></tr>
            <tr class="bt"><td class="bbd p bold" style="text-align: end;">Total :</td><td style="text-align: right;"><span class="angka">%@LW_PField_po_hrg-po_hpot-po_hpot2-po_hpot3-po_hpot4-po_hpot5+po_htax@%</span> Rp</td></tr>          
          </table>
        </td>
      </tr> 

    </tbody>
  </table>
  LW_prowno_299@%
</body>
%@LW_pgend@@
LW_pgend@%
</html>
```
